1	export function nextGeneration(livingCells: Set<string>): Set<string> {
2	  const nextGen = new Set<string>();
3	  for (const cell of cellsToEvaluate(livingCells)) {
4	    const liveNeighborCount = countLiveNeighbors(cell, livingCells);
5	    if (liveNeighborCount === 3 || (liveNeighborCount === 2 && livingCells.has(cell))) {
6	      nextGen.add(cell);
7	    }
8	  }
9	  return nextGen;
10	}
11	
12	function cellsToEvaluate(livingCells: Set<string>): Set<string> {
13	  const cells = new Set<string>();
14	  for (const cell of livingCells) {
15	    cells.add(cell);
16	    for (const neighbor of neighborsOf(cell)) cells.add(neighbor);
17	  }
18	  return cells;
19	}
20	
21	function countLiveNeighbors(cell: string, livingCells: Set<string>): number {
22	  let count = 0;
23	  for (const neighbor of neighborsOf(cell)) {
24	    if (livingCells.has(neighbor)) count++;
25	  }
26	  return count;
27	}
28	
29	function* neighborsOf(cell: string): Generator<string> {
30	  const [x, y] = cell.split(",").map(Number);
31	  for (let dx = -1; dx <= 1; dx++) {
32	    for (let dy = -1; dy <= 1; dy++) {
33	      if (dx === 0 && dy === 0) continue;
34	      yield `${x + dx},${y + dy}`;
35	    }
36	  }
37	}
